zigbee_status_t zigbee_join_network(void) {
    uint8_t attempt = 0;
    zigbee_status_t status;
    
    zigbee_indicate_joining(true);
    
    while (attempt < g_commissioning_config.max_join_attempts) {
        printf("[Zigbee] Join attempt %d/%d\n", attempt + 1, g_commissioning_config.max_join_attempts);
        
        status = zigbee_perform_network_discovery();
        if (status != ZIGBEE_STATUS_SUCCESS) {
            printf("[Zigbee] No networks found\n");
            attempt++;
            zigbee_delay_ms(2000);
            continue;
        }
        
        zigbee_network_descriptor_t *target_network = zigbee_select_best_network();
        if (target_network == NULL) {
            printf("[Zigbee] No suitable network found (PermitJoin may be disabled)\n");
            attempt++;
            zigbee_delay_ms(2000);
            continue;
        }
        
        g_device_info.state = ZIGBEE_STATE_JOINING;
        
        status = zigbee_send_association_request(target_network);
        if (status != ZIGBEE_STATUS_SUCCESS) {
            printf("[Zigbee] Failed to send association request\n");
            attempt++;
            continue;
        }
        
        uint32_t start_time = zigbee_get_tick_ms();
        uint32_t timeout = g_commissioning_config.join_timeout_seconds * 1000;
        
        while ((zigbee_get_tick_ms() - start_time) < timeout) {
            if (g_device_info.state == ZIGBEE_STATE_JOINED) {
                zigbee_indicate_joining(false);
                return ZIGBEE_STATUS_SUCCESS;
            }
            
            if (g_device_info.state == ZIGBEE_STATE_FAILED) {
                break;
            }
            
            zigbee_delay_ms(100);
        }
        
        attempt++;
    }
    
    printf("[Zigbee] Failed to join network after %d attempts\n", g_commissioning_config.max_join_attempts);
    g_device_info.state = ZIGBEE_STATE_FAILED;
    zigbee_indicate_joining(false);
    zigbee_indicate_joined(false);
    
    return ZIGBEE_STATUS_FAILURE;
}

zigbee_status_t zigbee_leave_network(void) {
    if (!g_device_info.joined) {
        return ZIGBEE_STATUS_FAILURE;
    }
    
    printf("[Zigbee] Leaving network...\n");
    
    uint8_t leave_request[] = {0x04, 0x00};
    zigbee_hardware_transmit(leave_request, sizeof(leave_request));
    
    g_device_info.joined = false;
    g_device_info.state = ZIGBEE_STATE_INIT;
    g_device_info.short_address = 0xFFFE;
    g_device_info.pan_id = 0xFFFF;
    
    memset(&g_network_key, 0, sizeof(zigbee_network_key_t));
    
    return ZIGBEE_STATUS_SUCCESS;
}

